async function run(input) {
  var color = String((input && input.color) || '').trim();
  var color2 = (input && input.color2) ? String(input.color2).trim() : '';
  function parse(c) {
    c = c.trim();
    var m = c.match(/^#?([0-9a-fA-F]{3})$/);
    if (m) {
      var s = m[1];
      return [parseInt(s[0] + s[0], 16), parseInt(s[1] + s[1], 16), parseInt(s[2] + s[2], 16)];
    }
    m = c.match(/^#?([0-9a-fA-F]{6})$/);
    if (m) {
      var h = m[1];
      return [parseInt(h.slice(0, 2), 16), parseInt(h.slice(2, 4), 16), parseInt(h.slice(4, 6), 16)];
    }
    m = c.match(/^rgba?\(\s*([0-9]{1,3})\s*,\s*([0-9]{1,3})\s*,\s*([0-9]{1,3})/i);
    if (m) {
      return [Number(m[1]), Number(m[2]), Number(m[3])];
    }
    return null;
  }
  function toHex(rgb) {
    return '#' + rgb.map(function (v) { return Math.max(0, Math.min(255, v)).toString(16).padStart(2, '0'); }).join('');
  }
  function toHsl(rgb) {
    var r = rgb[0] / 255, g = rgb[1] / 255, b = rgb[2] / 255;
    var max = Math.max(r, g, b), min = Math.min(r, g, b);
    var hue = 0, sat = 0, lum = (max + min) / 2;
    if (max !== min) {
      var d = max - min;
      sat = lum > 0.5 ? d / (2 - max - min) : d / (max + min);
      if (max === r) hue = (g - b) / d + (g < b ? 6 : 0);
      else if (max === g) hue = (b - r) / d + 2;
      else hue = (r - g) / d + 4;
      hue = hue / 6;
    }
    return 'hsl(' + Math.round(hue * 360) + ', ' + Math.round(sat * 100) + '%, ' + Math.round(lum * 100) + '%)';
  }
  function relLum(rgb) {
    var a = rgb.map(function (v) {
      var x = v / 255;
      return x <= 0.03928 ? x / 12.92 : Math.pow((x + 0.055) / 1.055, 2.4);
    });
    return 0.2126 * a[0] + 0.7152 * a[1] + 0.0722 * a[2];
  }
  var rgb1 = parse(color);
  if (!rgb1) return { fehler: 'Farbe nicht erkannt. Erlaubt: #rrggbb, #rgb, rgb(r,g,b).' };
  var result = {
    hex: toHex(rgb1),
    rgb: 'rgb(' + rgb1[0] + ', ' + rgb1[1] + ', ' + rgb1[2] + ')',
    hsl: toHsl(rgb1)
  };
  if (color2) {
    var rgb2 = parse(color2);
    if (!rgb2) return { fehler: 'Zweite Farbe nicht erkannt.' };
    var l1 = relLum(rgb1), l2 = relLum(rgb2);
    var lighter = Math.max(l1, l2), darker = Math.min(l1, l2);
    var ratio = (lighter + 0.05) / (darker + 0.05);
    ratio = Math.round(ratio * 100) / 100;
    result.kontrast = {
      verhaeltnis: ratio,
      AA_normal: ratio >= 4.5,
      AA_gross: ratio >= 3,
      AAA_normal: ratio >= 7
    };
  }
  return result;
}
